UPDATE public.admin_workouts
SET main_workout = $$<p class="tiptap-paragraph">🧽 <strong><u>Soft Tissue Preparation 5'</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:1511:hamstring stretch}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:1397:standing calves}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:1585:runners stretch}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:1352:lower back curl}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">Lacrosse ball work for hip flexors and deeper glute tissue (focused pressure for 30 sec)</p></li></ul><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">🔥 <strong><u>Activation 15'</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph"><strong>Movement Prep (5 min):</strong> 10 {{exercise:0514:jump squat}}, 15 reps walking lunge (each leg)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph"><strong>Dynamic Mobility (5 min):</strong> 10 reps per side squat to overhead reach with twist, 10 reps per side world greatest stretch</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph"><strong>Glute & Core Stability (5 min):</strong> 10 reps per side glute bridge march, 10 reps per side Fire Hydrant</p></li></ul><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">💪 <strong><u>Main Workout (REPS & SETS)</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">4 sets x 8-10 reps {{exercise:0696:self assisted inverse leg curl (on floor)}} (controlled tempo)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">3 sets x 12 reps per side {{exercise:1775:side plank hip adduction}} (pause at top)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">3 sets x 10 reps per leg {{exercise:3663:reverse plank with leg lift}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">Rest 90-120 seconds between sets for compound movements, 60-90 seconds for isolation.</p></li></ul><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">⚡ <strong><u>Finisher (REPS & SETS)</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">3 sets x 10 reps {{exercise:0513:jump squat v. 2}} (explosive)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">3 sets x 12 reps per side {{exercise:3645:single leg bridge with outstretched leg}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">3 sets x 15 reps {{exercise:1373:bodyweight standing calf raise}} (on a staircase) (controlled focus)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">Rest 60 seconds between sets.</p></li></ul><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">🧘 <strong><u>Cool Down 10'</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph"><strong>Static Stretching (8 min):</strong> 60 sec per leg leg up hamstring stretch, 60 sec per side seated glute stretch, 60 sec per leg lying (side) quads stretch</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph"><strong>Diaphragmatic Breathing (2 min):</strong> Lie supine, one hand on chest, one on belly. Slow inhale through nose (belly rises), slow exhale through mouth. Focus on calming nervous system.</p></li></ul>$$
WHERE id = 'WOD-S-B-1778577016745';